function DonutCard({ figNum, title, data }) {
  const total = data.reduce((s, d) => s + d.value, 0);
  return (
    <div className="log-card p-5">
      <div className="flex items-baseline gap-2 mb-2">
        <span className="fig-tag">FIG. {figNum}</span>
        <h3 className="chart-title">{title}</h3>
      </div>
      <ResponsiveContainer width="100%" height={280}>
        <PieChart>
          <Pie
            data={data}
            dataKey="value"
            nameKey="name"
            innerRadius={62}
            outerRadius={95}
            paddingAngle={1.5}
            stroke="var(--paper)"
            strokeWidth={2}
          >
            {data.map((_, i) => <Cell key={i} fill={PALETTE[i % PALETTE.length]} />)}
          </Pie>
          <Tooltip
            contentStyle={{ background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 4, fontSize: 12, fontFamily: "var(--font-body)" }}
            formatter={(v, n) => [`${v} (${((v / total) * 100).toFixed(0)}%)`, n]}
          />
          <Legend
            layout="vertical"
            verticalAlign="middle"
            align="right"
            wrapperStyle={{ fontSize: 11, fontFamily: "var(--font-mono)", color: "var(--ink-soft)" }}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
}

function intensityColor(value, max, baseColor) {
  if (value === 0) return "transparent";
  const t = Math.min(1, value / max);
  const alpha = 0.12 + t * 0.78;
  return `${baseColor}${Math.round(alpha * 255).toString(16).padStart(2, "0")}`;
}

function EquipmentCategoryHeatmap({ figNum, title }) {
  const { equipment_list, category_list, cells } = EXTRA.heatmap;
  const lookup = useMemo(() => {
    const m = {};
    cells.forEach((c) => { m[`${c.equipment}|${c.category}`] = c.count; });
    return m;
  }, []);
  const max = Math.max(...cells.map((c) => c.count));

  return (
    <div className="log-card p-5 md:col-span-2">
      <div className="flex items-baseline gap-2 mb-4">
        <span className="fig-tag">FIG. {figNum}</span>
        <h3 className="chart-title">{title}</h3>
      </div>
      <div className="overflow-x-auto">
        <table className="heatmap-table">
          <thead>
            <tr>
              <th></th>
              {category_list.map((c) => <th key={c}>{c}</th>)}
            </tr>
          </thead>
          <tbody>
            {equipment_list.map((eq) => (
              <tr key={eq}>
                <td className="row-label">{eq}</td>
                {category_list.map((cat) => {
                  const v = lookup[`${eq}|${cat}`] || 0;
                  return (
                    <td key={cat} title={`${eq} × ${cat}: ${v}`}>
                      <div className="heat-cell" style={{ background: intensityColor(v, max, "#2F6F4E") }}>
                        {v > 0 ? v : ""}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ConfusionMatrix({ figNum, title }) {
  const { classes, confusion } = EXTRA.confusion;
  const lookup = useMemo(() => {
    const m = {};
    confusion.forEach((c) => { m[`${c.true}|${c.pred}`] = c.count; });
    return m;
  }, []);
  const max = Math.max(...confusion.map((c) => c.count));

  return (
    <div className="log-card p-5 md:col-span-2">
      <div className="flex items-baseline gap-2 mb-1">
        <span className="fig-tag">FIG. {figNum}</span>
        <h3 className="chart-title">{title}</h3>
      </div>
      <p className="text-xs mb-4" style={{ color: "var(--ink-soft)" }}>
        Rows = true target muscle, columns = predicted. Diagonal is correct; off-diagonal cells show where the classifier confuses muscle groups.
      </p>
      <div className="overflow-x-auto">
        <table className="heatmap-table confusion">
          <thead>
            <tr>
              <th></th>
              {classes.map((c) => <th key={c}>{c.slice(0, 4)}</th>)}
            </tr>
          </thead>
          <tbody>
            {classes.map((trueCls) => (
              <tr key={trueCls}>
                <td className="row-label">{trueCls}</td>
                {classes.map((predCls) => {
                  const v = lookup[`${trueCls}|${predCls}`] || 0;
                  const isDiag = trueCls === predCls;
                  return (
                    <td key={predCls} title={`true: ${trueCls}, pred: ${predCls} → ${v}`}>
                      <div
                        className="heat-cell"
                        style={{ background: intensityColor(v, max, isDiag ? "#2F6F4E" : "#C1443B") }}
                      >
                        {v > 0 ? v : ""}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function PerClassF1Chart({ figNum, title }) {
  const data = EXTRA.confusion.per_class_f1;
  return (
    <div className="log-card p-5">
      <div className="flex items-baseline gap-2 mb-4">
        <span className="fig-tag">FIG. {figNum}</span>
        <h3 className="chart-title">{title}</h3>
      </div>
      <ResponsiveContainer width="100%" height={Math.max(240, data.length * 24)}>
        <BarChart data={data} layout="vertical" margin={{ top: 0, right: 30, left: 0, bottom: 0 }}>
          <CartesianGrid strokeDasharray="2 4" stroke="var(--line)" horizontal={false} />
          <XAxis type="number" domain={[0, 1]} tick={{ fontSize: 11, fill: "var(--ink-soft)" }} axisLine={{ stroke: "var(--line)" }} tickLine={false} />
          <YAxis
            type="category"
            dataKey="name"
            width={110}
            tick={{ fontSize: 11, fill: "var(--ink)", fontFamily: "var(--font-mono)" }}
            axisLine={{ stroke: "var(--line)" }}
            tickLine={false}
          />
          <Tooltip
            contentStyle={{ background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 4, fontSize: 12, fontFamily: "var(--font-body)" }}
            formatter={(v, n, p) => [`F1 ${v} · support ${p.payload.support}`, "score"]}
          />
          <Bar dataKey="f1" radius={[0, 4, 4, 0]} barSize={12}>
            {data.map((d, i) => (
              <Cell key={i} fill={d.f1 >= 0.75 ? "#2F6F4E" : d.f1 >= 0.5 ? "#E0A526" : "#C1443B"} />
            ))}
            <LabelList dataKey="f1" position="right" style={{ fontSize: 10, fill: "var(--ink-soft)", fontFamily: "var(--font-mono)" }} />
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

